// 1. جلب البيانات من العقدة السابقة (السياق الأساسي مثل email و expiry_time)
const c = $('Code: expiry_time = Now + 120s').first().json;

// 2. التقاط البيانات القادمة من Redis
const inputJson = $input.first().json;
const raw = inputJson.propertyName ?? inputJson.value ?? inputJson;

let state = {};

// 3. تحليل بيانات Redis بأمان
if (typeof raw === 'string' && raw.trim() !== '') {
  try { 
    state = JSON.parse(raw); 
  } catch { 
    state = {}; 
  }
} else if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
  state = raw;
}

// 4. استخراج القيم من Redis
const status = state.status ? String(state.status) : 'None';
const account_key = state.account_key ? String(state.account_key) : (c.account_key ? String(c.account_key) : '');
const fail_count = state.fail_count !== undefined ? Number(state.fail_count) : 0;

// ==========================================
// 5. التعديل الجديد: تحديد الـ Provider ديناميكياً
const currentEmail = String(state.email || c.email || '').toLowerCase();
const dynamicProvider = currentEmail.endsWith('@gmail.com') ? 'gmail' : 'mailtm';
// ==========================================

// 6. منطق حلقة التكرار (Loop Logic)
const timed_out = Date.now() > Number(c.expiry_time);

// ---> [التعديل الجذري]: فحص دقيق يضمن اكتشاف غياب البيانات حتى لو احتوى الكائن على بيانات أخرى (Metadata)
const is_empty = 
    inputJson.value === null || 
    raw === 'null' || 
    raw === null || 
    Object.keys(state).length === 0 || 
    (state.status === undefined && state.email === undefined); // إذا اختفت خصائصك الأساسية، فالبيانات تعتبر فارغة

// النجاح يتحقق إذا كان الـ status هو 'user_succeed' أو إذا كانت البيانات فارغة/تم استهلاكها
const user_succeed = status === 'user_succeed' || is_empty;

const continue_loop = !(timed_out || user_succeed);

let end_reason = 'running';

// إعطاء الأولوية للنجاح قبل التحقق من انتهاء الوقت
if (user_succeed) {
    end_reason = 'success';
} else if (timed_out) {
    end_reason = 'timeout';
}

// 7. دمج المخرجات وإرجاعها
return { 
  json: { 
    ...c, 
    status: status, 
    account_key: account_key, 
    fail_count: Number.isFinite(fail_count) ? fail_count : 0, 
    provider: dynamicProvider, 
    continue_loop: continue_loop, 
    end_reason: end_reason 
  } 
};

const items = $input.all();
const re = /\b\d{4}\b/;
const now = new Date();
const TWO_MINUTES_MS = 1 * 60 * 1000; // 2 minutes in milliseconds

for (const it of items) {
  const e = it.json;

  // 1. Get the exact time the email was received
  const emailTime = new Date(e.createdAt);

  // 2. Calculate how old the email is in milliseconds
  const ageMs = now - emailTime;

  // 3. ONLY process the email if it arrived less than 2 minutes ago
  if (ageMs <= TWO_MINUTES_MS) {
    const txt = `${e.subject || ''} ${e.intro || ''}`;
    const isDisney = txt.toLowerCase().includes('disney') || 
                     (e.from && e.from.name && String(e.from.name).toLowerCase().includes('disney'));

    if (isDisney) {
      const m = txt.match(re);
      if (m) {
        // Found a fresh code! Returning it.
        return { 
          json: { 
            found: true, 
            code: m[0], 
            source: 'mailtm', 
            age_seconds: Math.floor(ageMs / 1000) // Helpful for debugging
          } 
        };
      }
    }
  }
}

// If the loop finishes and no emails from the last 2 minutes matched, return false
return { 
  json: { 
    found: false, 
    code: null, 
    source: 'mailtm',
    reason: 'no_recent_email'
  } 
};

