// 1. جلب العنصر من الطابور بأمان
const item = $input.first().json.next_queue_item;

// 2. التحقق مما إذا كان فارغاً تماماً
if (!item) {
  return { 
    json: { 
      is_valid_next: false, 
      email: '', 
      order_number: '', 
      phone: '', 
      conversation_id: null, 
      chatwoot_account_id: null 
    } 
  };
}

let p = {};

// 3. التحليل الذكي: هل هو نص يحتاج إلى Parse أم كائن جاهز؟
if (typeof item === 'string' && item.trim() !== '') {
  try { 
    p = JSON.parse(item); 
  } catch { 
    p = {}; 
  }
} else if (typeof item === 'object') {
  p = item; // إذا كان كائناً، خذه كما هو بدون أي تحويل
}

// 4. استخراج البيانات مع الحماية من القيم الفارغة
const email = String(p.email || '').trim().toLowerCase();
const order_number = String(p.order_number || '').trim();
const phone = String(p.phone || '').trim();
const conversation_id = p.conversation_id ?? null;
const chatwoot_account_id = p.chatwoot_account_id ?? null;

// 5. التأكد من وجود البيانات الأساسية لاعتبار العنصر صالحاً
const is_valid_next = Boolean(email && order_number);

// 6. الإرجاع النهائي
return { 
  json: { 
    ...p, 
    email, 
    order_number, 
    phone, 
    conversation_id, 
    chatwoot_account_id, 
    is_valid_next 
  } 
};

